#!/usr/bin/env python3
# /// script
# requires-python = ">=3.10"
# dependencies = ["mcp>=1.2", "uvicorn", "starlette"]
# ///
"""
Serveur MCP de banc d'essai pour MIAOU (V2 — délégation distante).

Transport streamable-http (single endpoint POST, réponses en SSE). CORS ouvert
pour permettre au navigateur de l'atteindre directement depuis dist/miaou.html.

Outils exposés :
  - echo(text)            : renvoie le texte (bloc text → réinjecté au modèle, D9)
  - add(a, b)             : somme (text)
  - dns_lookup(hostname)  : résolution DNS locale (text) — clin d'œil home bench
  - reverse_dns(ip)       : résolution inverse (PTR) d'une adresse IP
  - get_image()           : un PNG inline (bloc image → cascade D8.1, UI-only)
  - get_json_resource()   : une resource texte JSON (cascade D8.2, surlignée UI)

Lancement :
    uv run tests/mcp_bench.py            # écoute sur 127.0.0.1:8765
    uv run tests/mcp_bench.py 0.0.0.0 8765   # toutes interfaces, même port

Dans MIAOU → Paramètres → Serveurs MCP → Ajouter :
    Nom       : bench
    URL       : http://127.0.0.1:8765/mcp
    Transport : streamable-http   (deviné depuis /mcp)
    Activé    : oui
Les outils apparaissent préfixés  bench__echo, bench__get_image, …

NB CORS : si tu sers MIAOU derrière Caddy sur un autre host, ce serveur autorise
déjà toute origine + les headers Authorization / Mcp-Session-Id. En prod tu
mettrais ce backend derrière le même proxy (token côté serveur), cf. brief D6.
"""

import asyncio
import base64
import socket
import sys

from mcp import types
from mcp.server.fastmcp import FastMCP, Image
from mcp.server.transport_security import TransportSecuritySettings
from starlette.middleware.cors import CORSMiddleware

# Un PNG 256x128 (dégradé bleu/violet, diagonales, cercle orange) pour tester D8.1.
_RED_PNG_B64 = (
    ""
)

# MIAOU chargé en file:// envoie « Origin: null » → la protection anti-DNS-
# rebinding du SDK MCP renvoie 403 avant même la couche CORS. On la désactive
# pour le banc d'essai (réseau local de confiance, mono-utilisateur). En prod
# derrière proxy, on la garderait active avec un allowed_origins explicite.
_security = TransportSecuritySettings(enable_dns_rebinding_protection=False)

mcp = FastMCP("miaou-bench", transport_security=_security)


@mcp.tool()
async def echo(text: str) -> str:
    """Renvoie le texte fourni tel quel. Outil de fumée pour vérifier la délégation."""
    await asyncio.sleep(2)
    return text


@mcp.tool()
async def add(a: float, b: float) -> str:
    """Additionne deux nombres et renvoie le résultat."""
    await asyncio.sleep(2)
    return f"{a} + {b} = {a + b}"


@mcp.tool()
async def dns_lookup(hostname: str) -> str:
    """Résout un nom d'hôte en adresse(s) IP depuis le réseau local du serveur."""
    await asyncio.sleep(2)
    try:
        infos = socket.getaddrinfo(hostname, None)
        addrs = sorted({i[4][0] for i in infos})
        return f"{hostname} → " + ", ".join(addrs) # type: ignore
    except OSError as e:
        return f"Échec de résolution de {hostname} : {e}"


@mcp.tool()
async def reverse_dns(ip: str) -> str:
    """Résout une adresse IP en nom d'hôte (PTR) depuis le réseau local du serveur."""
    await asyncio.sleep(2)
    try:
        hostname, _, _ = socket.gethostbyaddr(ip)
        return f"{ip} → {hostname}"
    except OSError as e:
        return f"Échec de résolution inverse de {ip} : {e}"


@mcp.tool()
async def get_image() -> Image:
    """Renvoie une petite image PNG (test de la cascade de rendu non-text, D8.1)."""
    await asyncio.sleep(2)
    return Image(data=base64.b64decode(_RED_PNG_B64), format="png")


@mcp.tool()
async def get_json_resource() -> types.EmbeddedResource:
    """Renvoie une resource texte JSON embarquée (cascade D8.2, surlignage UI).

    On renvoie un vrai EmbeddedResource (pas un dict, que FastMCP sérialiserait en
    bloc `text` réinjecté au modèle) pour exercer le chemin non-text de MIAOU."""
    await asyncio.sleep(2)
    return types.EmbeddedResource(
        type="resource",
        resource=types.TextResourceContents(
            uri="miaou://bench/sample.json", # type: ignore
            mimeType="application/json",
            text='{\n  "ok": true,\n  "items": [1, 2, 3],\n  "note": "rendu via Prism côté MIAOU"\n}',
        ),
    )


def main() -> None:
    host = sys.argv[1] if len(sys.argv) > 1 else "127.0.0.1"
    port = int(sys.argv[2]) if len(sys.argv) > 2 else 8765

    app = mcp.streamable_http_app()
    app.add_middleware(
        CORSMiddleware,
        allow_origins=["*"],
        allow_methods=["GET", "POST", "OPTIONS", "DELETE"],
        allow_headers=["*"],
        expose_headers=["Mcp-Session-Id"],
    )

    import uvicorn

    print(f"MCP bench → http://{host}:{port}/mcp  (Ctrl-C pour arrêter)")
    uvicorn.run(app, host=host, port=port, log_level="info")


if __name__ == "__main__":
    main()
